import UIKit

// MARK: - Universal Link Route

enum DeepLinkRoute {
    case resetPassword(token: String)
    case unknown
}

// MARK: - Universal Link Parser

struct UniversalLinkParser {
    
    private static let allowedHost = "myapp.com"
    private static let resetPasswordPath = "/reset-password"
    private static let tokenKey = "token"
    
    // Token validation: alphanumeric, hyphens, underscores, dots; 10-256 chars
    private static let tokenPattern = "^[a-zA-Z0-9\\-_\\.]{10,256}$"
    
    static func parse(url: URL) -> DeepLinkRoute {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .unknown
        }
        
        // Validate scheme
        guard components.scheme == "https" else {
            return .unknown
        }
        
        // Validate host to prevent open redirect / spoofing
        guard let host = components.host?.lowercased(), host == allowedHost else {
            return .unknown
        }
        
        // Route based on path
        switch components.path {
        case resetPasswordPath:
            return parseResetPassword(from: components)
        default:
            return .unknown
        }
    }
    
    private static func parseResetPassword(from components: URLComponents) -> DeepLinkRoute {
        guard let queryItems = components.queryItems,
              let tokenItem = queryItems.first(where: { $0.name == tokenKey }),
              let token = tokenItem.value,
              !token.isEmpty else {
            return .unknown
        }
        
        // Sanitize and validate token format
        let sanitizedToken = token.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard isValidToken(sanitizedToken) else {
            return .unknown
        }
        
        return .resetPassword(token: sanitizedToken)
    }
    
    private static func isValidToken(_ token: String) -> Bool {
        guard let regex = try? NSRegularExpression(pattern: tokenPattern) else {
            return false
        }
        let range = NSRange(token.startIndex..<token.endIndex, in: token)
        return regex.firstMatch(in: token, range: range) != nil
    }
}

// MARK: - Deep Link Navigator

protocol DeepLinkNavigating: AnyObject {
    func navigateToResetPassword(token: String)
    func navigateToHome()
    func showError(message: String)
}

final class DeepLinkNavigator: DeepLinkNavigating {
    
    private weak var window: UIWindow?
    private let navigationController: UINavigationController
    
    init(window: UIWindow?, navigationController: UINavigationController) {
        self.window = window
        self.navigationController = navigationController
    }
    
    func navigateToResetPassword(token: String) {
        // Dismiss any presented view controllers first
        navigationController.presentedViewController?.dismiss(animated: false)
        
        // Pop to root to ensure clean navigation state
        navigationController.popToRootViewController(animated: false)
        
        let resetVC = PasswordResetViewController(token: token)
        navigationController.pushViewController(resetVC, animated: true)
    }
    
    func navigateToHome() {
        navigationController.popToRootViewController(animated: true)
    }
    
    func showError(message: String) {
        let alert = UIAlertController(
            title: "Error",
            message: message,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        navigationController.present(alert, animated: true)
    }
}

// MARK: - Deep Link Handler

final class DeepLinkHandler {
    
    private let navigator: DeepLinkNavigating
    
    // Rate limiting: track reset attempts
    private var lastResetAttempt: Date?
    private let minimumInterval: TimeInterval = 2.0 // seconds between attempts
    
    init(navigator: DeepLinkNavigating) {
        self.navigator = navigator
    }
    
    func handle(url: URL) -> Bool {
        let route = UniversalLinkParser.parse(url: url)
        
        switch route {
        case .resetPassword(let token):
            return handleResetPassword(token: token)
        case .unknown:
            return false
        }
    }
    
    private func handleResetPassword(token: String) -> Bool {
        // Rate limiting check
        if let lastAttempt = lastResetAttempt,
           Date().timeIntervalSince(lastAttempt) < minimumInterval {
            navigator.showError(message: "Please wait before trying again.")
            return true
        }
        
        lastResetAttempt = Date()
        navigator.navigateToResetPassword(token: token)
        return true
    }
}

